Sure, here's a basic Java implementation of a blockchain that demonstrates the core principles of a blockchain. This code uses SHA-256 as the hashing algorithm and a simple proof of work algorithm for consensus. Note that this code is not optimized for production use and is not a complete or secure implementation.

```
import java.util.ArrayList;
import java.util.Date;

public class Block {
    private String previousHash;
    private ArrayList<Transaction> transactions;
    private int nonce;
    private long timestamp;
    private String hash;

    public Block(String previousHash) {
        this.previousHash = previousHash;
        this.transactions = new ArrayList<Transaction>();
        this.timestamp = new Date().getTime();
        this.hash = calculateHash();
    }

    public String calculateHash() {
        String data = previousHash + transactions.toString() + nonce + timestamp;
        return SHA256(data);
    }

    public String mineBlock(int difficulty) {
        String target = new String(new char[difficulty]).replace('\0', '0');
        while(!hash.substring(0, difficulty).equals(target)) {
            nonce++;
            hash = calculateHash();
        }
        return hash;
    }

    public void addTransaction(Transaction transaction) {
        transactions.add(transaction);
    }

    private String SHA256(String data) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(data.getBytes(StandardCharsets.UTF_8));
            StringBuffer hexString = new StringBuffer();
            for (int i = 0; i < hash.length; i++) {
                String hex = Integer.toHexString(0xff & hash[i]);
                if(hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }
            return hexString.toString();
        } catch(Exception ex) {
            throw new RuntimeException(ex);
        }
    }
}

public class Blockchain {
    private ArrayList<Block> chain;
    private int difficulty;

    public Blockchain() {
        this.chain = new ArrayList<Block>();
        this.difficulty = 4; // Change this value to adjust mining difficulty
        createGenesisBlock();
    }

    public void createGenesisBlock() {
        Block genesisBlock = new Block("0");
        chain.add(genesisBlock);
    }

    public Block getLatestBlock() {
        return chain.get(chain.size() - 1);
    }

    public void addBlock(Block newBlock) {
        newBlock.mineBlock(difficulty);
        chain.add(newBlock);
    }

    public boolean isChainValid() {
        for (int i = 1; i < chain.size(); i++) {
            Block currentBlock = chain.get(i);
            Block previousBlock = chain.get(i - 1);

            if (!currentBlock.hash.equals(currentBlock.calculateHash())) {
                return false;
            }

            if (!currentBlock.previousHash.equals(previousBlock.hash)) {
                return false;
            }

            if (!currentBlock.hash.substring(0, difficulty).equals(new String(new char[difficulty]).replace('\0', '0'))) {
                return false;
            }
        }

        return true;
    }
}

public class Transaction {
    private String from;
    private String to;
    private double amount;
    private Date timestamp;

    public Transaction(String from, String to, double amount) {
        this.from = from;
        this.to = to;
        this.amount = amount;
        this.timestamp = new Date();
    }

    public String getFrom() {
        return from;
    }

    public String getTo() {
        return to;
    }

    public double getAmount() {
        return amount;
    }

    public Date getTimestamp() {
        return timestamp;
    }
}

public class Main {
    public static void main(String[] args) {
        Blockchain chain = new Blockchain();

        // Add some transactions
        chain.getLatestBlock().addTransaction(new Transaction("Alice", "Bob", 1.0));
        chain.getLatestBlock().addTransaction(new Transaction("Bob", "Charlie", 2.0));

        // Add a new block containing the above transactions
        Block block = new Block(chain.getLatestBlock().hash);
        block.addTransaction(new Transaction("Charlie", "David", 3.0));
        chain.addBlock(block);

        // Print the blockchain
        for (Block b : chain.chain) {
            System.out.println("Block #" + chain.chain.indexOf(b));
            System.out.println("Hash: " + b.hash);
            System.out.println("Previous Hash: " + b.previousHash);
            System.out.println("Timestamp: " + b.timestamp);
            System.out.println("Nonce: " + b.nonce);
            System.out.println("Transactions: " + b.transactions.toString());
            System.out.println();
        }

        // Check if the blockchain is valid
        System.out.println("Blockchain is valid: " + chain.isChainValid());
    }
}
```

Note: Please keep in mind that this is a basic implementation, a lot of important aspects of the blockchain is missing in the code, for example, Merkle Trees, Transactions and the Implementation of the consensus algorithm.
